type PersistenceScope int64 //gd:OpenXRSpatialAnchorCapability.PersistenceScope

const (
	// Provides the application with read-only access (i.e. application cannot modify this scope) to spatial entities persisted and managed by the system. The application can use the UUID in the persistence component for this scope to correlate entities across spatial contexts and device reboots.
	PersistenceScopeSystemManaged PersistenceScope = 1
	// Persistence operations and data access is limited to spatial anchors, on the same device, for the same user and same app (using [PersistAnchor] and [UnpersistAnchor] functions)
	//
	// [PersistAnchor]: https://pkg.go.dev/graphics.gd/classdb/#Instance.PersistAnchor
	// [UnpersistAnchor]: https://pkg.go.dev/graphics.gd/classdb/#Instance.UnpersistAnchor
	PersistenceScopeLocalAnchors PersistenceScope = 1000781000
)
